import re
def norm_doc(d):
    return re.sub(r"[^0-9a-z]", "", d.casefold())

def blocking_key(rec):
    return rec.get("apellido", "").casefold() + "|" + rec.get("region", "").casefold()

def er_score(a, b):
    if norm_doc(a.get("doc", "")) and norm_doc(a.get("doc", "")) == norm_doc(b.get("doc", "")):
        if blocking_key(a) == blocking_key(b):
            return 1.0
    if blocking_key(a) == blocking_key(b):
        return 0.5
    return 0.0

a = {"doc": "12345678", "apellido": "Quispe", "region": "LIM"}
b = {"doc": "1234-5678", "apellido": "Quispe", "region": "LIM"}
print(er_score(a, b))

