def direct_txs(txs, a, b):
    out = []
    for x, y, m in txs:
        if {x, y} == {a, b}:
            out.append(m)
    return out

print(direct_txs(txs, "A", "B"))

txs = [("A","D",1), ("C","D",1), ("A","E",1), ("C","F",1)]
def neighbors(txs, node):
    s = set()
    for x, y, _ in txs:
        if x == node:
            s.add(y)
        elif y == node:
            s.add(x)
    return s

def common_counterparties(txs, a, c):
    return sorted(neighbors(txs, a) & neighbors(txs, c) - {a, c})

print(common_counterparties(txs, "A", "C"))

def uncertainty_band(missing, conflict):
    if conflict or len(missing) >= 2:
        return "high"
    if missing:
        return "med"
    return "low"

print(uncertainty_band([], False), "|", uncertainty_band(["a"], False), "|",
      uncertainty_band(["a", "b"], False), "|", uncertainty_band([], True))

