from math import isfinite

th = {"accept_min": 0.8, "review_low": 0.4}

def decide_ops_status(score, unc, th):
    if not isinstance(score, (int, float)) or isinstance(score, bool):
        return "invalid_input"
    if not isfinite(score) or not (0.0 <= float(score) <= 1.0):
        return "invalid_input"
    if unc not in {"low", "med", "high"}:
        return "invalid_input"
    if unc == "high":
        return "needs_review"
    if score < th["review_low"]:
        return "abstain"
    if score < th["accept_min"]:
        return "needs_review"
    return "accept_pair"

cases = [
    (-0.1, "low"),
    (0.399, "low"),
    (0.4, "low"),
    (0.799, "low"),
    (0.8, "low"),
    (1.0, "low"),
    (0.9, "high"),
    (float("nan"), "low"),
    (0.5, "?"),
]
for s, u in cases:
    print(s, u, decide_ops_status(s, u, th))

